31	
32	  describe("Quote — item-specific modifiers", () => {
33	    it.todo("cursed sword (steel, ench 3, year 0, first contract) returns 165 G (100 + 50 curse + 10 first-insurance + 5 fee)");
34	    it.todo("cursed sword + plain amulet (year 0, first contract) returns 231 G (curse applies only to sword: 100+50+60 base + 10+6 first-ins + 5 fee)");
