39	
40	  describe("Quote — policy-wide modifiers", () => {
41	    it.todo("2-year customer with plain sword, first contract returns 95 G (100 + 10 first-ins − 20 loyalty + 5 fee)");
42	    it.todo("3-year customer's second quote of cursed sword ench 7 returns 160 G (100 + 50 curse + 30 high-ench + 10 first-ins − 20 loyalty − 15 follow-up + 5 fee)");
43	  });
44	
45	  describe("Claim — standard reimbursement and deductible", () => {
46	    it.todo("steel sword ench 3 damaged 500 G returns payout 400 G and remainingCap 1600 (cap 2000 − 400)");
47	    it.todo("rune damaged 200 G returns payout 100 G and remainingCap 400 (cap 500 − 100; no special clause for components)");
48	    it.todo("dragon attack damages sword 500 G + amulet 300 G returns payout 600 G (deductible per damage event: 400 + 200)");
49	  });
50	
51	  describe("Claim — special reimbursement clauses", () => {
52	    it.todo("steel sword ench 9 damaged 1000 G returns payout 400 G (50% rule then deductible)");
53	    it.todo("dragon-material sword ench 5 damaged 800 G returns payout 700 G (full reimbursement then deductible)");
54	    it.todo("dragon-material sword ench 9 damaged 1000 G returns payout 400 G (both clauses: 50% wins, then deductible)");
55	    it.todo("dragon-material sword ench exactly 8 damaged 1000 G returns payout 400 G (50% applies at threshold)");
