57	
58	  describe("Claim — cap behavior", () => {
59	    it.todo("sword insured; two successive 1500 G claims: first payout 1400 remainingCap 600, second payout 600 remainingCap 0");
60	    it.todo("cursed sword's cap remains 2000 G (premium modifiers do not raise the cap)");
61	    it.todo("sword + 3 runes: insurance sum 1750 G, cap 3500 G (block discount affects premium only, not insurance sum)");
62	    it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G; both damaged 500 G each returns payout 800 G");
