1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	
22	export function quote(_customer: Customer, items: Item[]): number {
23	  const itemsTotal = items.reduce((sum, item) => {
24	    const base = BASE_PREMIUMS[item.type];
25	    return sum + base + base * FIRST_INSURANCE_RATE;
26	  }, 0);
27	  return itemsTotal + PROCESSING_FEE;
28	}
